// ═══════════════════════════════════════════════════════════════
// NODO: Detect_Changes_And_Prepare_Sync
// ═══════════════════════════════════════════════════════════════

const payload = $json.user_request.payload;
const original = $json.catalog;
const owner = $json.owner_data;

const hasChanged = (a, b) => JSON.stringify(a) !== JSON.stringify(b);

// 1. MAPPATURA INTEGRALE 1:1
const diff = {
  identity: {
    name: hasChanged(payload.identity.item_name, original.identity.item_name),
    desc_short: hasChanged(payload.identity.description.short, original.identity.description.short),
    desc_long: hasChanged(payload.identity.description.long, original.identity.description.long)
  },
  pricing: {
    price: hasChanged(payload.pricing.base_price, original.pricing.base_price)
  },
  commercial: {
    extras: hasChanged(payload.commercial_setup?.extra_options, original.commercial_setup?.extra_options)
  },
  operations: {
    booking: hasChanged(payload.operations.requires_booking, original.operations.requires_booking),
    // QUESTO È QUELLO CHE CAMBIA NEL TUO JSON (False -> True)
    inventory: hasChanged(payload.operations.requires_inventory_check, original.operations.requires_inventory_check)
  }
};

// 2. DECISIONE LOGICA
// Qualsiasi modifica deve far proseguire il workflow per salvare sul DB
const has_changes = diff.identity.name || diff.identity.desc_short || diff.identity.desc_long || 
                    diff.pricing.price || diff.commercial.extras || 
                    diff.operations.booking || diff.operations.inventory;

// Solo le modifiche "semantiche" richiedono l'IA (Gemini)
const needs_ai_sync = diff.identity.name || diff.identity.desc_long || 
                      diff.pricing.price || diff.commercial.extras;

// 3. PREPARA IL SOMMARIO PER IL LOG / IA
const summary = [];
if (diff.identity.name) summary.push("Nome prodotto");
if (diff.pricing.price) summary.push("Prezzo base");
if (diff.commercial.extras) summary.push("Opzioni Extra/Add-ons");
if (diff.operations.inventory) summary.push("Stato Inventario (Update Tecnico)");

return [{
  json: {
    owner_data: owner,
    modified_catalog: payload,
    original_catalog: original,
    changes_detail: diff,
    changes_summary: summary,
    has_changes: has_changes,      // Sarà TRUE (perché l'inventario è cambiato)
    needs_sync: needs_ai_sync,    // Sarà FALSE (se è cambiato SOLO l'inventario)
    item_sku: payload.identity.item_sku,
    catalog_session_id: $json.user_request.chat_id
  }
}];

