const BOT_TOKEN = "8378810625:AAHK3Zya8qFKD4OzFBbwSTOAGolDeY7jiJQ";
const initData = $input.item.json.body._auth;

if (!initData) return { isValid: false, error: "Dato _auth mancante" };

// --- 2. LIBRERIA CRIPTOGRAFICA PURE JS (SHA-256 & HMAC) ---
const CryptoJS = (function() {
    function sha256(m) {
        var h = [0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19];
