// NODO: Delta Merger Engine
// OBIETTIVO: Applicare patch chirurgiche ai documenti JSON usando la sintassi stile MongoDB (dot notation + array filters)

const item = $input.first().json;

// --- 1. SAFETY FIRST: CLONAZIONE PROFONDA ---
// Lavoriamo su copie per non corrompere i dati di input originali nel flusso n8n
let finalBlueprint = item.blueprint ? JSON.parse(JSON.stringify(item.blueprint)) : null;
let finalKb = item.KbFragment ? JSON.parse(JSON.stringify(item.KbFragment)) : null;
const finalProduct = item.modified_catalog; 
const delta = item.delta_update;

// --- 2. HELPER FUNCTIONS ---

/**
 * Recupera il valore di una proprietà annidata (es. "metadata.status")
 */
function getNestedValue(obj, path) {
    if (!path || !obj) return undefined;
    return path.split('.').reduce((acc, part) => (acc && acc[part] !== undefined) ? acc[part] : undefined, obj);
}

/**
 * Trova l'indice di un elemento in un array basandosi sui filtri (alias)
 * Es: cerca in 'currentArray' l'elemento che soddisfa il filtro associato all'alias "$[kb_sec]"
 */
function findIndexByFilter(currentArray, alias, filters) {
    if (!Array.isArray(currentArray) || !filters) return -1;

    // 1. Trova il filtro corrispondente all'alias (es. cerca chiave che inizia con "kb_sec.")
    const filterObj = filters.find(f => {
        const key = Object.keys(f)[0];
        return key.startsWith(alias + '.');
    });

    if (!filterObj) {
        // Se non c'è filtro esplicito ma l'array è semplice, potremmo loggare un warning
        return -1;
    }

    const filterKeyFull = Object.keys(filterObj)[0]; // es. "kb_sec.question"
    const expectedValue = filterObj[filterKeyFull];  // es. "Testo della domanda..."

    // 2. Determina il nome della proprietà reale nell'oggetto (rimuovi "kb_sec.")
    // "kb_sec.question" -> "question"
    // "bp_stage.stage_id" -> "stage_id"
    const propertyName = filterKeyFull.substring(alias.length + 1);

    // 3. Cerca l'elemento
    return currentArray.findIndex(el => {
        const val = getNestedValue(el, propertyName);
        return val === expectedValue;
    });
}

/**
 * Motore principale di aggiornamento
 * @param {Object} doc - Il documento da modificare (blueprint o kb)
 * @param {String} path - Il percorso (es. "stages.$[bp_stage].steps.$[bp_step].instructions")
 * @param {Any} value - Il nuovo valore
 * @param {Array} filters - L'array dei filtri per risolvere gli alias
 */
function applyUpdate(doc, path, value, filters) {
    if (!doc) return;

    const parts = path.split('.');
    let current = doc;

    for (let i = 0; i < parts.length; i++) {
        const part = parts[i];
        const isLast = i === parts.length - 1;

        // CASO A: Array Placeholder (es. "$[kb_sec]")
        if (part.startsWith('$[')) {
            // Estrai alias senza dollari e parentesi: "$[kb_sec]" -> "kb_sec"
            const alias = part.match(/\$\[(.*?)\]/)[1];

            // L'oggetto corrente DEVE essere un array qui
            if (Array.isArray(current)) {
                const idx = findIndexByFilter(current, alias, filters);

                if (idx !== -1) {
                    if (isLast) {
                        current[idx] = value; // Sostituzione intero oggetto (raro)
                    } else {
                        current = current[idx]; // Entriamo nell'oggetto trovato
                    }
                } else {
                    // Elemento non trovato: Interrompiamo in sicurezza
                    // console.log(`Merge Skip: Elemento non trovato per alias ${alias}`);
                    return; 
                }
            } else {
                return; // Errore strutturale (ci aspettavamo array)
            }
        } 
        // CASO B: Proprietà Standard
        else {
            if (isLast) {
                // ASSEGNAZIONE FINALE
                current[part] = value;
            } else {
                // Navigazione
                // Se il prossimo step non esiste, potremmo doverlo creare (qui assumiamo struttura esistente)
                if (current[part] === undefined) {
                    // Se stiamo scrivendo, forse dovremmo creare l'oggetto? 
                    // Per ora usiamo logica strict: se non esiste il path, non scriviamo.
                    return; 
                }
                current = current[part];
            }
        }
    }
}

// --- 3. ESECUZIONE LOGICA ---

// Applicazione Update KB
if (delta && delta.kb_fragment_updates && delta.kb_fragment_updates.updates) {
    const updates = delta.kb_fragment_updates.updates;
    const filters = delta.kb_fragment_updates.array_filters || [];

    Object.keys(updates).forEach(path => {
        applyUpdate(finalKb, path, updates[path], filters);
    });
}

// Applicazione Update Blueprint
if (delta && delta.blueprint_updates && delta.blueprint_updates.updates) {
    const updates = delta.blueprint_updates.updates;
    const filters = delta.blueprint_updates.array_filters || [];

    Object.keys(updates).forEach(path => {
        applyUpdate(finalBlueprint, path, updates[path], filters);
    });
}

// --- 4. COSTRUZIONE OUTPUT PER TELEGRAPH/DB ---

return {
    json: {
        // I dati "fusi" e aggiornati
        Final_KB_Fragment: finalKb,
        Final_Blueprint: finalBlueprint,
        Final_Product: finalProduct,

        // Metadati utili per il nodo Telegraph successivo
        page_title: `KB: ${finalProduct.identity.item_name}`,

        // Debug Info
        sync_info: {
            was_updated: true,
            reason: delta?.sync_summary?.reasoning || "Manual Sync",
            timestamp: new Date().toISOString()
        },

        // Mantengo il contesto originale se servisse
        ...item
    }
};

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Save_Confirmation_Simple
// DESC: Esito Sincronizzazione - Ritorno alla scheda operativa
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero Dati Core
const owner = item.owner_data || {};
const payload = item.body.payload || {};
const delta = item.delta_update || {};
const tx = item.transaction_summary || {};
const catalog = item.service_catalog_setup?.categories || [];

const sku = item.body.sop_id;
const mId = item.body.message_id;

// 2. Lookup Nome Esteso (Zero ID Tecnici nel testo)
let extendedName = sku;
for (const cat of catalog) {
    const subFound = cat.subcategories.find(sub => sub.callback_data === sku);
    if (subFound) {
        extendedName = subFound.name;
        break;
    }
}

// 3. Analisi Cambiamenti e Reasoning AI
const changes = item.changes_summary || [];
let changesList = changes.length > 0 
    ? changes.map(c => ` ├ ${c}`).join("\n") 
    : " ├ Nessuna variazione strutturale rilevata.";

const syncReasoning = delta.sync_summary?.reasoning || "Sincronizzazione completata con successo.";

// 4. Localizzazione
const L = (owner.lenguage || 'it').toLowerCase().includes('en') ? 'en' : 'it';
const t = {
    it: {
        title: "✅ <b>AGGIORNAMENTO COMPLETATO</b>",
        project: `PROGETTO: <b>${extendedName.toUpperCase()}</b>`,
        header_changes: "📊 <b>MODIFICHE APPLICATE:</b>",
        header_reason: "🧠 <b>REASONING SINCRONIZZAZIONE (AI):</b>",
        footer: `Costo: <code>${tx.credits_deducted} Cr.</code> | Saldo: <b>${tx.final_balance}</b>`,
        btn_back: "⬅️ Torna alla Procedura"
    },
    en: {
        title: "✅ <b>UPDATE COMPLETED</b>",
        project: `PROJECT: <b>${extendedName.toUpperCase()}</b>`,
        header_changes: "📊 <b>APPLIED CHANGES:</b>",
        header_reason: "🧠 <b>SYNC REASONING (AI):</b>",
        footer: `Cost: <code>${tx.credits_deducted} Cr.</code> | Balance: <b>${tx.final_balance}</b>`,
        btn_back: "⬅️ Back to Procedure"
    }
}[L];

// 5. Composizione Messaggio HTML
const messageText = `
${t.title}
━━━━━━━━━━━━━━━━━━━━
${t.project}

${t.header_changes}
${changesList}

${t.header_reason}
<i>"${syncReasoning}"</i>

━━━━━━━━━━━━━━━━━━━━
⛽ ${t.footer}`;

// 6. Payload Telegram (EDIT del messaggio corrente)
const telegramApiPayload = {
    method: "editMessageText",
    chat_id: owner.chat_id,
    message_id: mId,
    text: messageText,
    parse_mode: "HTML",
    reply_markup: {
        inline_keyboard: [
            [{ text: t.btn_back, callback_data: `get_active_sop_${sku}` }]
        ]
    }
};

return [{ json: { ...item, telegramApiPayload: telegramApiPayload } }];
